class Solution {
    /**
     * Calculates the degree of each vertex in a graph represented by an adjacency matrix.
     *
     * @param matrix The n x n adjacency matrix of the undirected graph.
     * @return An array of length n, where ans[i] is the degree of vertex i.
     */
    public static long[] solve(long[][] matrix) {
        if (matrix == null || matrix.length == 0) {
            return new long[0];
        }

        int n = matrix.length;
        long[] ans = new long[n];

        for (int i = 0; i < n; i++) {
            long degree = 0;
            for (int j = 0; j < n; j++) {
                // Since matrix[i][j] is 1 if there is an edge, we sum up the row entries.
                // We don't need to worry about self-loops (matrix[i][i] == 0) based on the constraints.
                if (matrix[i][j] == 1) {
                    degree++;
                }
            }
            ans[i] = degree;
        }

        return ans;
    }
}
